import{_ as l,o as a,c as e,a3 as n}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"工作区基础","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/workspace-basics.md","filePath":"user-guide/workspace-basics.md","lastUpdated":1778221347000}'),r={name:"user-guide/workspace-basics.md"};function s(o,t,i,d,g,h){return a(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="工作区基础" tabindex="-1">工作区基础 <a class="header-anchor" href="#工作区基础" aria-label="Permalink to &quot;工作区基础&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>工作区</strong> 就是你在 AIO Hub 中看到的整个界面——它是你与所有工具交互的大本营。理解工作区的各个区域和操作方式，能让你在使用过程中更加得心应手。</p><p>简单来说，AIO Hub 的工作区由三个核心部分组成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    标题栏                        │</span></span>
<span class="line"><span>├──────────┬───────────────────────────────────────┤</span></span>
<span class="line"><span>│          │                                       │</span></span>
<span class="line"><span>│  侧边栏  │            主内容区域                 │</span></span>
<span class="line"><span>│  (导航)  │     (工具页面 / 聊天 / 设置)          │</span></span>
<span class="line"><span>│          │                                       │</span></span>
<span class="line"><span>│          │                                       │</span></span>
<span class="line"><span>└──────────┴───────────────────────────────────────┘</span></span></code></pre></div><ul><li><strong>标题栏</strong>：顶部区域，显示当前页面名称，提供主题切换、通知、设置、窗口控制等全局操作入口。</li><li><strong>侧边栏</strong>：左侧区域，用于管理已打开的工具标签页，支持折叠和多种显示模式。</li><li><strong>主内容区</strong>：占据最大面积的中央区域，所有工具页面都在这里打开和运行。</li></ul><blockquote><p>💡 <strong>小贴士</strong>：标题栏和侧边栏的背景具有通透感。如果你开启了 <strong>UI 模糊</strong> 并设置了应用壁纸，它们会透出应用内部壁纸；如果你开启了 <strong>窗口特效</strong>（如 Windows 的 Mica 或 macOS 的模糊），它们甚至能透出你的系统桌面背景。</p></blockquote><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><blockquote><p>跟着下面的步骤走一遍，你就能熟悉工作区的基本操作了。</p></blockquote><h3 id="_1-认识你的界面" tabindex="-1">1. 认识你的界面 <a class="header-anchor" href="#_1-认识你的界面" aria-label="Permalink to &quot;1. 认识你的界面&quot;">​</a></h3><p>启动 AIO Hub 后，你会看到这样的主界面：</p><p>![主界面标注](TODO: 截图-标注出标题栏、侧边栏和主内容区的位置)</p><ul><li><strong>左侧</strong>一列图标就是侧边栏，显示你当前已打开的工具。</li><li><strong>顶部</strong>一条是标题栏。</li><li><strong>中间</strong>大片区域是主内容区，默认显示<strong>主页</strong>，你可以在这里看到所有可用的工具。</li></ul><h3 id="_2-打开一个工具" tabindex="-1">2. 打开一个工具 <a class="header-anchor" href="#_2-打开一个工具" aria-label="Permalink to &quot;2. 打开一个工具&quot;">​</a></h3><ol><li>在<strong>主页</strong>中找到你想要使用的工具卡片。</li><li>点击工具卡片，该工具将会在主内容区打开。</li><li>同时，该工具的图标会出现在左侧的<strong>侧边栏</strong>中。</li></ol><p>![打开工具](TODO: 截图-在主页点击工具卡片打开)</p><h3 id="_3-同时打开多个工具" tabindex="-1">3. 同时打开多个工具 <a class="header-anchor" href="#_3-同时打开多个工具" aria-label="Permalink to &quot;3. 同时打开多个工具&quot;">​</a></h3><p>AIO Hub 支持多标签页架构——你可以同时打开多个工具，并在侧边栏中快速切换。</p><ol><li>点击侧边栏顶部的 <strong>🏠 主页</strong> 图标回到主页。</li><li>点击另一个工具卡片。</li><li>新工具会打开，且侧边栏会增加一个新的工具图标。</li><li>你可以通过点击侧边栏中的不同图标来切换工具。</li></ol><p>![多工具切换](TODO: 截图-点击侧边栏不同图标切换已打开的工具)</p><h3 id="_4-关闭工具" tabindex="-1">4. 关闭工具 <a class="header-anchor" href="#_4-关闭工具" aria-label="Permalink to &quot;4. 关闭工具&quot;">​</a></h3><p>当某个工具用完后，可以关闭它：</p><ul><li>在侧边栏中，鼠标悬停在工具名称上，右边会出现一个 <strong>×</strong> 按钮，点击即可关闭</li><li>或者在工具图标上 <strong>右键点击</strong>，选择「关闭标签页」</li></ul><p>![关闭工具](TODO: 截图-鼠标悬停在侧边栏工具上，显示关闭按钮)</p><h3 id="_5-进入设置" tabindex="-1">5. 进入设置 <a class="header-anchor" href="#_5-进入设置" aria-label="Permalink to &quot;5. 进入设置&quot;">​</a></h3><p>点击侧边栏底部或标题栏右侧的 <strong>⚙️ 设置</strong> 图标，进入设置页面。这里可以配置 LLM 服务、调整外观等。</p><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="🟦-标题栏" tabindex="-1">🟦 标题栏 <a class="header-anchor" href="#🟦-标题栏" aria-label="Permalink to &quot;🟦 标题栏&quot;">​</a></h3><p>标题栏是工作区的&quot;控制中心&quot;，所有全局操作都能在这里完成。</p><p>![标题栏区域标注](TODO: 截图-标题栏标注出各个区域)</p><h4 id="左侧-品牌与导航" tabindex="-1">左侧：品牌与导航 <a class="header-anchor" href="#左侧-品牌与导航" aria-label="Permalink to &quot;左侧：品牌与导航&quot;">​</a></h4><ul><li><strong>品牌标识</strong>：左侧显示 AIO Hub 的 Logo 和名称</li><li><strong>菜单按钮</strong>：如果你在设置中将侧边栏切换为「下拉菜单」或「抽屉」模式，左侧会出现一个菜单按钮（☰），点击即可展开导航</li></ul><blockquote><p>侧边栏的显示模式可以在 <strong>设置 → 外观 → 侧边栏模式</strong> 中调整，有三种可选：</p><ul><li><strong>固定侧边栏</strong>（默认）：侧边栏始终显示在左侧</li><li><strong>下拉菜单</strong>：点击标题栏左侧按钮展开导航</li><li><strong>抽屉</strong>：点击标题栏左侧按钮从左侧滑出导航</li></ul></blockquote><h4 id="中间-当前页面标题" tabindex="-1">中间：当前页面标题 <a class="header-anchor" href="#中间-当前页面标题" aria-label="Permalink to &quot;中间：当前页面标题&quot;">​</a></h4><p>显示当前正在使用的工具名称。如果你打开了不同工具，标题会相应变化。</p><h4 id="右侧-全局操作区" tabindex="-1">右侧：全局操作区 <a class="header-anchor" href="#右侧-全局操作区" aria-label="Permalink to &quot;右侧：全局操作区&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">按钮</th><th style="text-align:left;">功能</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">👤</td><td style="text-align:left;"><strong>用户档案</strong></td><td style="text-align:left;">选择不同角色与 AI 对话，每个档案有独立的名字和头像</td></tr><tr><td style="text-align:left;">🌓</td><td style="text-align:left;"><strong>主题切换</strong></td><td style="text-align:left;">快速切换浅色 / 深色 / 跟随系统。点击后下拉菜单可选</td></tr><tr><td style="text-align:left;">📥</td><td style="text-align:left;"><strong>下载管理</strong></td><td style="text-align:left;">查看和管理文件下载进度与历史（如未显示可在设置中开启）</td></tr><tr><td style="text-align:left;">🔔</td><td style="text-align:left;"><strong>消息通知</strong></td><td style="text-align:left;">查看系统推送的通知消息（如任务完成提醒）</td></tr><tr><td style="text-align:left;">⚙️</td><td style="text-align:left;"><strong>设置</strong></td><td style="text-align:left;">进入设置页面配置各项参数</td></tr><tr><td style="text-align:left;"><strong>—</strong></td><td style="text-align:left;"><strong>最小化</strong></td><td style="text-align:left;">将应用最小化到任务栏</td></tr><tr><td style="text-align:left;"><strong>□</strong></td><td style="text-align:left;"><strong>最大化/还原</strong></td><td style="text-align:left;">在窗口模式和全屏之间切换</td></tr><tr><td style="text-align:left;"><strong>×</strong></td><td style="text-align:left;"><strong>关闭/隐藏到托盘</strong></td><td style="text-align:left;">关闭窗口。如果开启了「最小化到托盘」，点击后会隐藏到系统托盘</td></tr></tbody></table><blockquote><p>💡 <strong>macOS 用户请注意</strong>：在 macOS 上，标题栏左侧会预留空间给原生的&quot;红绿灯&quot;按钮（关闭/最小化/最大化），窗口控制按钮会由系统提供，因此标题栏右侧不会显示这些按钮。</p></blockquote><h4 id="分离窗口的标题栏" tabindex="-1">分离窗口的标题栏 <a class="header-anchor" href="#分离窗口的标题栏" aria-label="Permalink to &quot;分离窗口的标题栏&quot;">​</a></h4><p>当你把一个工具拖拽成独立窗口后，分离窗口也有自己的标题栏，但内容略有不同：</p><ul><li>显示该工具的名称和图标</li><li>右侧多了一个 <strong>↩ 回归主窗口</strong> 按钮，点击即可将工具放回主窗口</li></ul><hr><h3 id="🟩-侧边栏" tabindex="-1">🟩 侧边栏 <a class="header-anchor" href="#🟩-侧边栏" aria-label="Permalink to &quot;🟩 侧边栏&quot;">​</a></h3><p>侧边栏是工作区的“活动中心”，它以标签页的形式管理你当前正在使用的工具。</p><h4 id="侧边栏结构" tabindex="-1">侧边栏结构 <a class="header-anchor" href="#侧边栏结构" aria-label="Permalink to &quot;侧边栏结构&quot;">​</a></h4><p>侧边栏中从上到下依次排列：</p><ul><li><strong>🏠 主页</strong> — 点击返回工具平铺主页，从这里打开新工具。</li><li><strong>🧩 扩展</strong> — 管理和浏览插件市场（功能还在开发中）。</li><li><strong>已打开的工具</strong> — 你当前打开的工具图标会显示在这里，带有激活状态指示。</li></ul><p>![侧边栏拆解](TODO: 截图-在侧边栏上标注出各部分说明)</p><h4 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">怎么做</th><th style="text-align:left;">效果</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>切换工具</strong></td><td style="text-align:left;">左键点击已打开的工具图标</td><td style="text-align:left;">主内容区切换到该工具页面</td></tr><tr><td style="text-align:left;"><strong>关闭工具</strong></td><td style="text-align:left;">鼠标悬停在图标上，点击右侧 <strong>×</strong></td><td style="text-align:left;">关闭该工具标签页（仅展开模式）</td></tr><tr><td style="text-align:left;"><strong>调整顺序</strong></td><td style="text-align:left;"><strong>长按并拖动</strong> 工具图标</td><td style="text-align:left;">上下移动调整工具在侧边栏的排列顺序</td></tr><tr><td style="text-align:left;"><strong>分离窗口</strong></td><td style="text-align:left;"><strong>右键点击</strong> → 在新窗口中打开</td><td style="text-align:left;">把工具拖拽为独立窗口</td></tr><tr><td style="text-align:left;"><strong>分离窗口</strong></td><td style="text-align:left;"><strong>按住并向右拖拽</strong> 图标超过 40px</td><td style="text-align:left;">快速将工具分离为独立窗口（仅限 Windows）</td></tr><tr><td style="text-align:left;"><strong>更多操作</strong></td><td style="text-align:left;"><strong>右键点击</strong> 工具图标</td><td style="text-align:left;">弹出菜单：分离窗口或关闭标签页</td></tr></tbody></table><blockquote><p>💡 <strong>小贴士</strong>：侧边栏收起时，为了节省空间，关闭按钮会隐藏，此时请通过<strong>右键菜单</strong>来关闭工具。</p></blockquote><hr><h3 id="⬜-主内容区" tabindex="-1">⬜ 主内容区 <a class="header-anchor" href="#⬜-主内容区" aria-label="Permalink to &quot;⬜ 主内容区&quot;">​</a></h3><p>主内容区是工作区中占比最大的区域，所有工具都在这里运行。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="🪟-多窗口模式" tabindex="-1">🪟 多窗口模式 <a class="header-anchor" href="#🪟-多窗口模式" aria-label="Permalink to &quot;🪟 多窗口模式&quot;">​</a></h3><p>AIO Hub 最强大的特性之一就是能把任意工具<strong>创建成独立窗口</strong>。这在多任务处理时特别好用。</p><h4 id="触发分离的方式" tabindex="-1">触发分离的方式 <a class="header-anchor" href="#触发分离的方式" aria-label="Permalink to &quot;触发分离的方式&quot;">​</a></h4><p>AIO Hub 提供两种便捷方式将工具分离为独立窗口：</p><ul><li><strong>快捷拖拽</strong>：在侧边栏找到工具图标，<strong>按住鼠标左键向右拖拽</strong>超过 40px，工具会自动“弹出”为独立窗口。 <ul><li>⚠️ <strong>注意</strong>：由于系统兼容性限制，目前<strong>快捷拖拽</strong>主要支持 Windows 系统。macOS 用户由于系统交互冲突，该功能已被禁用，请统一使用右键菜单进行分离。</li></ul></li><li><strong>右键菜单</strong>：在侧边栏工具图标上点击<strong>右键</strong>，选择「在新窗口中打开」。</li></ul><h4 id="场景示例" tabindex="-1">场景示例 <a class="header-anchor" href="#场景示例" aria-label="Permalink to &quot;场景示例&quot;">​</a></h4><ul><li><strong>一边聊天一边查资料</strong>：将 <strong>LLM 聊天</strong> 分离到副屏，主窗口保持打开浏览器或文档工具。</li><li><strong>同时对比两个工具</strong>：将 <strong>JSON 格式化</strong> 分离，主窗口打开 <strong>文本差异对比</strong>，实现跨窗口的数据处理。</li></ul><h4 id="恢复分离窗口" tabindex="-1">恢复分离窗口 <a class="header-anchor" href="#恢复分离窗口" aria-label="Permalink to &quot;恢复分离窗口&quot;">​</a></h4><p>当需要将工具收回到主窗口时，可以使用以下方式：</p><ul><li><strong>回归按钮</strong>：点击分离窗口标题栏右侧的 <strong>↩ 回归主窗口</strong> 按钮。</li><li><strong>直接关闭</strong>：直接关闭分离窗口，工具会自动回到主窗口的侧边栏中。</li></ul><blockquote><p>💡 所有分离窗口的位置和大小都会被自动记住，下次启动应用时会恢复到上次的位置。</p></blockquote><hr><h3 id="🎨-个性化工作区" tabindex="-1">🎨 个性化工作区 <a class="header-anchor" href="#🎨-个性化工作区" aria-label="Permalink to &quot;🎨 个性化工作区&quot;">​</a></h3><p>想让工作区看起来更&quot;属于你&quot;？试试这些：</p><table tabindex="0"><thead><tr><th style="text-align:left;">设置项</th><th style="text-align:left;">怎么调</th><th style="text-align:left;">效果</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>主题模式</strong></td><td style="text-align:left;">设置 → 外观 → 主题</td><td style="text-align:left;">浅色 / 深色 / 跟随系统</td></tr><tr><td style="text-align:left;"><strong>界面质感</strong></td><td style="text-align:left;">设置 → 外观 → 界面质感</td><td style="text-align:left;">调整内部 UI 透明度、毛玻璃强度</td></tr><tr><td style="text-align:left;"><strong>窗口特效</strong></td><td style="text-align:left;">设置 → 外观 → 窗口特效</td><td style="text-align:left;">启用系统级模糊、亚克力或云母效果</td></tr><tr><td style="text-align:left;"><strong>壁纸</strong></td><td style="text-align:left;">设置 → 外观 → 壁纸管理</td><td style="text-align:left;">选择内置壁纸或上传自定义图片</td></tr><tr><td style="text-align:left;"><strong>侧边栏模式</strong></td><td style="text-align:left;">设置 → 外观 → 侧边栏模式</td><td style="text-align:left;">固定侧边栏 / 下拉菜单 / 抽屉</td></tr></tbody></table><p>![外观设置](TODO: 截图-设置页面中的外观设置区域)</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-我不小心把工具拖拽成独立窗口了-怎么恢复" tabindex="-1">Q1：我不小心把工具拖拽成独立窗口了，怎么恢复？ <a class="header-anchor" href="#q1-我不小心把工具拖拽成独立窗口了-怎么恢复" aria-label="Permalink to &quot;Q1：我不小心把工具拖拽成独立窗口了，怎么恢复？&quot;">​</a></h3><p>别担心，有几种方式可以恢复：</p><ol><li>点击分离窗口标题栏右侧的 <strong>↩ 回归主窗口</strong> 按钮</li><li>直接关闭分离窗口，工具会自动回到主窗口的侧边栏中</li></ol><h3 id="q2-侧边栏太宽了-能缩窄一点吗" tabindex="-1">Q2：侧边栏太宽了，能缩窄一点吗？ <a class="header-anchor" href="#q2-侧边栏太宽了-能缩窄一点吗" aria-label="Permalink to &quot;Q2：侧边栏太宽了，能缩窄一点吗？&quot;">​</a></h3><p>可以。侧边栏支持<strong>折叠模式</strong>：</p><ol><li>点击侧边栏底部的 <strong>◀</strong> 按钮</li><li>侧边栏会收缩为只显示图标的一窄条</li><li>再次点击 <strong>▶</strong> 按钮即可展开</li></ol><p>如果你想完全隐藏侧边栏，可以在 <strong>设置 → 外观 → 侧边栏模式</strong> 中切换为「下拉菜单」或「抽屉」模式。</p><h3 id="q3-我可以自定义侧边栏中工具的顺序吗" tabindex="-1">Q3：我可以自定义侧边栏中工具的顺序吗？ <a class="header-anchor" href="#q3-我可以自定义侧边栏中工具的顺序吗" aria-label="Permalink to &quot;Q3：我可以自定义侧边栏中工具的顺序吗？&quot;">​</a></h3><p>可以。在侧边栏中<strong>长按</strong>任意工具图标，然后<strong>上下拖动</strong>即可调整顺序。松开鼠标后位置就被记住了，下次启动应用时顺序不变。</p><h3 id="q4-同时打开太多工具-主内容区标签页太多了怎么办" tabindex="-1">Q4：同时打开太多工具，主内容区标签页太多了怎么办？ <a class="header-anchor" href="#q4-同时打开太多工具-主内容区标签页太多了怎么办" aria-label="Permalink to &quot;Q4：同时打开太多工具，主内容区标签页太多了怎么办？&quot;">​</a></h3><ul><li><strong>关闭不用的工具</strong>：在侧边栏右键工具图标，点击菜单中的 <code>关闭标签页</code>。在展开模式下可以直接点击标签上的 <strong>X</strong> 关闭。</li></ul><h3 id="q5-为什么我的标题栏-侧边栏没有毛玻璃效果" tabindex="-1">Q5：为什么我的标题栏/侧边栏没有毛玻璃效果？ <a class="header-anchor" href="#q5-为什么我的标题栏-侧边栏没有毛玻璃效果" aria-label="Permalink to &quot;Q5：为什么我的标题栏/侧边栏没有毛玻璃效果？&quot;">​</a></h3><p>AIO Hub 的“模糊”分为两种，请根据你的需求检查设置：</p><h4 id="情况-a-你想透出-应用内的壁纸-ui-模糊" tabindex="-1">情况 A：你想透出“应用内的壁纸” (UI 模糊) <a class="header-anchor" href="#情况-a-你想透出-应用内的壁纸-ui-模糊" aria-label="Permalink to &quot;情况 A：你想透出“应用内的壁纸” (UI 模糊)&quot;">​</a></h4><p>这种效果是在应用内部实现的，你需要：</p><ol><li>在 <strong>外观 → 壁纸管理</strong> 中开启壁纸，并选一张图。</li><li>在 <strong>外观 → 界面质感</strong> 中开启「启用 UI 特效」和「UI 模糊」。</li><li>调低「UI 基础不透明度」滑块。 <em>注：如果不设置应用壁纸，UI 模糊将没有背景可滤，看起来就是纯色。</em></li></ol><h4 id="情况-b-你想透出-系统桌面背景-窗口特效" tabindex="-1">情况 B：你想透出“系统桌面背景” (窗口特效) <a class="header-anchor" href="#情况-b-你想透出-系统桌面背景-窗口特效" aria-label="Permalink to &quot;情况 B：你想透出“系统桌面背景” (窗口特效)&quot;">​</a></h4><p>这种效果由操作系统提供，具有更原生的质感：</p><ol><li>在 <strong>外观 → 窗口特效</strong> 中开启开关。</li><li>在「窗口背景特效」下拉框中选择 <strong>模糊 (Blur)</strong>、<strong>亚克力 (Acrylic)</strong> 或 <strong>云母 (Mica)</strong>。</li><li>开启「窗口背景不透明度」并调低滑块。</li><li><strong>关键点</strong>：在「界面质感」中将 <strong>壁纸不透明度</strong> 调低（甚至设为 0），否则应用内的壁纸会挡住窗口背后的画面。 <em>注：此功能为实验性，且在 Linux 系统上暂不可用。</em></li></ol><hr><blockquote><p>下一步：想了解工作区中的各个工具怎么用？请参考 <a href="./tools/">工具总览</a>。</p></blockquote>`,96)])])}const c=l(r,[["render",s]]);export{u as __pageData,c as default};
